            <div className="text-6xl mb-6">🍽️</div>
            <h1 className="text-3xl font-bold text-gray-800 mb-3">
              스마트 푸드 매니저
            </h1>
            <p className="text-gray-600 text-lg">
              AI로 똑똑하게 식사 계획하기
            </p>
          </div>

          <div className="space-y-6">
            <button
              onClick={startHomeCooking}
              className="w-full bg-white rounded-2xl shadow-lg p-8 transition-all duration-300 hover:shadow-xl hover:scale-105 active:scale-95"
            >
              <div className="flex items-center gap-6">
                <div className="bg-green-100 rounded-full p-4">
                  <CookingIcon />
                </div>
                <div className="text-left flex-1">
                  <h3 className="text-xl font-semibold text-gray-800 mb-1">해먹기</h3>
                  <p className="text-gray-600">냉장고 식재료로 요리하기</p>
                </div>
                <div className="text-gray-400 text-xl">→</div>
              </div>
            </button>

            <button
              onClick={startEating}
              className="w-full bg-white rounded-2xl shadow-lg p-8 transition-all duration-300 hover:shadow-xl hover:scale-105 active:scale-95"
            >
              <div className="flex items-center gap-6">
                <div className="bg-orange-100 rounded-full p-4">
                  <EatingIcon />
                </div>
                <div className="text-left flex-1">
                  <h3 className="text-xl font-semibold text-gray-800 mb-1">사먹기</h3>
                  <p className="text-gray-600">맛집 추천 및 주문하기</p>
                </div>
                <div className="text-gray-400 text-xl">→</div>
              </div>
            </button>
          </div>

          <div className="mt-12 text-center">
            <button
              onClick={testServerConnection}
              className="text-gray-500 hover:text-gray-700 underline transition-colors"
            >
              서버 연결 테스트
            </button>
          </div>
        </div>
      </div>
    );
  }

  // 사먹기 모드
  if (currentMode === 'eating') {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center p-4">
        <div className="text-center">
          <div className="text-6xl mb-6">🚧</div>
          <h2 className="text-2xl font-semibold text-gray-800 mb-4">사먹기 기능 개발 중</h2>
          <p className="text-gray-600 mb-8 text-lg">곧 멋진 기능으로 찾아뵙겠습니다!</p>
          <button
            onClick={goToHome}
            className="px-8 py-3 bg-blue-600 text-white rounded-xl hover:bg-blue-700 transition-colors text-lg font-medium"
          >
            홈으로 돌아가기
          </button>
        </div>
      </div>
    );
  }

  // 해먹기 모드 메인 화면
  return (
    <div className="min-h-screen bg-gray-50" style={{ paddingBottom: 'env(safe-area-inset-bottom)' }}>
      <div className="w-full max-w-7xl mx-auto p-4">
        
        {/* 헤더 */}
        <div className="bg-white rounded-2xl shadow-sm p-6 mb-6">
          <div className="flex items-center gap-4 mb-3">
            <button
              onClick={goToHome}
              className="p-3 hover:bg-gray-100 rounded-xl transition-colors"
            >
              <BackIcon />
            </button>
            <CookingIcon />
            <h1 className="text-2xl font-bold text-gray-800 flex-1">
              해먹기 - 냉장고 식재료 분석
            </h1>
          </div>
          <p className="text-gray-600 ml-16">
            냉장고 사진을 찍어서 식재료를 자동으로 인식해보세요
          </p>
        </div>

        {/* 액션 버튼들 */}
        <div className="bg-white rounded-2xl shadow-sm p-6 mb-6">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-6">
            <input
              type="file"
              accept="image/*"
              onChange={handleImageLoad}
              ref={fileInputRef}
              className="hidden"
            />
            
            <button
              onClick={() => fileInputRef.current?.click()}
              className="flex items-center justify-center gap-3 py-4 px-6 bg-blue-600 text-white rounded-xl font-medium transition-all duration-200 active:scale-95 hover:bg-blue-700 text-lg"
            >
              <UploadIcon />
              <span>이미지 업로드</span>
            </button>

            <button
              onClick={runIngredientAnalysis}
              disabled={!currentImage || isProcessing}
              className="flex items-center justify-center gap-3 py-4 px-6 bg-green-600 text-white rounded-xl font-medium transition-all duration-200 active:scale-95 hover:bg-green-700 disabled:bg-gray-400 disabled:cursor-not-allowed text-lg"
            >
              {isProcessing ? <LoadingSpinner /> : <BrainIcon />}
              <span>식재료 분석</span>
            </button>
          </div>

          {/* 냉장고 저장 및 불러오기 버튼들 */}
          {showSaveButton && (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-6 p-4 bg-green-50 border border-green-200 rounded-xl">
              <button
                onClick={saveToMongoDB}
                disabled={isSaving || fridgeIngredients.length === 0}
                className="flex items-center justify-center gap-3 py-4 px-6 bg-green-600 text-white rounded-xl font-medium transition-all duration-200 active:scale-95 hover:bg-green-700 disabled:bg-gray-400 disabled:cursor-not-allowed"
              >
                {isSaving ? <LoadingSpinner /> : <SaveIcon />}
                <span>
                  {isSaving ? '저장 중...' : `냉장고 저장 (${fridgeIngredients.length}종류)`}
                </span>
              </button>

              <button
                onClick={loadFromMongoDB}
                className="flex items-center justify-center gap-3 py-4 px-6 bg-blue-600 text-white rounded-xl font-medium transition-all duration-200 active:scale-95 hover:bg-blue-700"
              >
                <CheckIcon />
                <span>데이터 불러오기</span>
              </button>
            </div>
          )}

          {/* 신뢰도 설정 */}
          <div className="flex items-center gap-4 mb-4">
            <div className="flex items-center gap-3 min-w-fit">
              <SettingsIcon />
              <span className="font-medium text-gray-700 whitespace-nowrap">신뢰도</span>
            </div>
            <div className="flex-1 px-3">
              <input
                type="range"
                min="0.1"
                max="0.9"
                step="0.1"
                value={confidence}
                onChange={(e) => setConfidence(parseFloat(e.target.value))}
                className="w-full h-3 bg-gray-200 rounded-lg appearance-none cursor-pointer"
              />
            </div>
            <span className="font-medium text-gray-600 min-w-[3rem] text-center text-lg">
              {confidence.toFixed(1)}
            </span>
          </div>

          {/* 분석 전 초기화 옵션 */}
          <div className="flex items-center gap-4 pt-4 border-t border-gray-200">
            <label className="flex items-center gap-3 cursor-pointer">
              <input
                type="checkbox"
                checked={clearBeforeAnalysis}
                onChange={(e) => setClearBeforeAnalysis(e.target.checked)}
                className="w-5 h-5 text-blue-600 bg-gray-100 border-gray-300 rounded focus:ring-blue-500"
              />
              <span className="text-gray-700">분석 전 냉장고 초기화</span>
            </label>
            <div className="text-sm text-gray-500">
              (동일 이미지 재분석 시 중복 방지)
            </div>
          </div>
        </div>

        {/* 메인 콘텐츠 */}
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          
          {/* 이미지 표시 영역 */}
          <div className="lg:col-span-2">
            <div className="bg-white rounded-2xl shadow-sm p-6">
              <div 
                className={`border-2 border-dashed rounded-2xl min-h-[300px] lg:min-h-[500px] flex items-center justify-center transition-all duration-300 cursor-pointer ${
                  isDragOver 
                    ? 'border-blue-500 bg-blue-50' 
                    : 'border-gray-300 hover:border-blue-400 hover:bg-blue-50'
                }`}
                onDragOver={handleDragOver}
                onDragLeave={handleDragLeave}
                onDrop={handleDrop}
                onClick={() => fileInputRef.current?.click()}
              >
                {currentImage ? (
                  <img
                    src={currentImage}
                    alt="Uploaded"
                    className="max-w-full max-h-full rounded-xl object-contain"
                    style={{ maxHeight: '70vh' }}
                  />
                ) : (
                  <div className="text-center text-gray-500 p-8">
                    <div className="text-6xl mb-4">🧊</div>
                    <p className="text-xl font-medium mb-2">
                      {isDragOver ? '파일을 놓아주세요' : '냉장고 사진을 업로드하세요'}
                    </p>
                    <p className="text-gray-400">
                      {isDragOver ? '' : '업로드 후 "식재료 분석" 버튼 클릭'}
                    </p>
                  </div>
                )}
              </div>

              {/* 진행 상태 */}
              {isProcessing && (
                <div className="mt-6 bg-blue-50 border border-blue-200 rounded-xl p-4">
                  <div className="flex items-center gap-4">
                    <LoadingSpinner />
                    <span className="text-blue-800 font-medium">{processingStep}</span>
                  </div>
                </div>
              )}
            </div>
          </div>

          {/* 결과 표시 영역 */}
          <div className="lg:col-span-1">
            {/* 냉장고 속 식재료 대시보드 */}
            <div className="bg-white rounded-2xl shadow-sm mb-6">
              <div className="p-6 border-b border-gray-200">
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-3">
                    <FridgeIcon />
                    <h3 className="text-xl font-semibold text-gray-800">냉장고 속 식재료</h3>
                  </div>
                  <div className="flex items-center gap-4">
                    <button
                      onClick={() => setFridgeIngredients([])}
                      className="text-sm text-red-500 hover:text-red-700 hover:bg-red-50 px-3 py-2 rounded-lg transition-colors"
                    >
                      전체 삭제
                    </button>
                    <div className="text-gray-500 font-medium">
                      총 {fridgeIngredients.length}개
                    </div>
                  </div>
                </div>
              </div>
              <div className="p-6" style={{ minHeight: '300px', maxHeight: '500px', overflowY: 'auto' }}>
                {fridgeIngredients.length > 0 ? (
                  <div className="space-y-4">
                    {fridgeIngredients.map((ingredient) => (
                      <div key={ingredient.id} className="bg-gradient-to-r from-blue-50 to-green-50 border border-gray-200 rounded-xl p-5 transition-all duration-200 hover:shadow-md">
                        <div className="flex items-center justify-between mb-4">
                          <h4 className="font-semibold text-gray-800 text-lg">{ingredient.name}</h4>
                          <button
                            onClick={() => removeIngredient(ingredient.id)}
                            className="text-red-500 hover:text-red-700 hover:bg-red-50 rounded-full p-2 transition-colors"
                          >
                            <DeleteIcon />
                          </button>
                        </div>
                        
                        <div className="flex items-center justify-between">
                          <div className="flex items-center gap-4">
                            <button
                              onClick={() => updateIngredientQuantity(ingredient.id, ingredient.quantity - 1)}
                              disabled={ingredient.quantity <= 1}
                              className="w-10 h-10 rounded-full bg-red-100 text-red-600 hover:bg-red-200 disabled:bg-gray-100 disabled:text-gray-400 disabled:cursor-not-allowed flex items-center justify-center transition-colors text-lg"
                            >
                              <MinusIcon />
                            </button>
                            
                            <div className="flex flex-col items-center">
                              <span className="text-3xl font-bold text-blue-600">{ingredient.quantity}</span>
                              <span className="text-sm text-gray-500">개</span>
                            </div>
                            
                            <button
                              onClick={() => updateIngredientQuantity(ingredient.id, ingredient.quantity + 1)}
                              className="w-10 h-10 rounded-full bg-green-100 text-green-600 hover:bg-green-200 flex items-center justify-center transition-colors text-lg"
                            >
                              <PlusIcon />
                            </button>
                          </div>
                          
                          <div className="text-sm text-gray-500 bg-white bg-opacity-70 px-3 py-2 rounded-full">
                            {(ingredient.source === 'ocr' || ingredient.source === 'ocr_smart') && '📄 OCR'}
                            {ingredient.source === 'detection' && '🎯 탐지'}
                            {ingredient.source === 'analysis' && '🧠 AI'}
                            {ingredient.confidence && (
                              <span className="ml-2 text-green-600 font-semibold">
                                {(ingredient.confidence * 100).toFixed(0)}%
                              </span>
                            )}
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>
                ) : (
                  <div className="text-center text-gray-500 py-16">
                    <div className="text-5xl mb-6">🥬</div>
                    <h4 className="text-xl font-medium mb-3">냉장고가 비어있습니다</h4>
                    <p className="text-gray-400">냉장고 사진을 업로드하고<br/>"식재료 분석" 버튼을 클릭하세요</p>
                  </div>
                )}
              </div>
              
              {fridgeIngredients.length > 0 && (
                <div className="px-6 py-4 bg-gray-50 border-t border-gray-200 rounded-b-2xl">
                  <div className="flex items-center justify-between">
                    <span className="text-gray-600 font-medium">총 수량</span>
                    <span className="font-bold text-gray-800 text-lg">
                      {fridgeIngredients.reduce((sum, item) => sum + item.quantity, 0)}개
                    </span>
                  </div>
                </div>
              )}
            </div>

            {/* 탭 네비게이션 */}
            <div className="bg-white rounded-2xl shadow-sm overflow-hidden">
              <div className="flex border-b border-gray-200">
                <button
                  onClick={() => setActiveTab('detection')}
                  className={`flex-1 py-4 px-4 font-medium transition-colors ${
                    activeTab === 'detection' 
                      ? 'bg-blue-50 text-blue-600 border-b-2 border-blue-600' 
                      : 'text-gray-500 hover:text-gray-700'
                  }`}
                >
                  <div className="flex items-center justify-center gap-2">
                    <EyeIcon />
                    <span>탐지</span>
                  </div>
                </button>
                
                <button
                  onClick={() => setActiveTab('ocr')}
                  className={`flex-1 py-4 px-4 font-medium transition-colors ${
                    activeTab === 'ocr' 
                      ? 'bg-purple-50 text-purple-600 border-b-2 border-purple-600' 
                      : 'text-gray-500 hover:text-gray-700'
                  }`}
                >
                  <div className="flex items-center justify-center gap-2">
                    <FileTextIcon />
                    <span>OCR</span>
                  </div>
                </button>
                
                <button
                  onClick={() => setActiveTab('gemini')}
                  className={`flex-1 py-4 px-4 font-medium transition-colors ${
                    activeTab === 'gemini' 
                      ? 'bg-green-50 text-green-600 border-b-2 border-green-600' 
                      : 'text-gray-500 hover:text-gray-700'
                  }`}
                >
                  <div className="flex items-center justify-center gap-2">
                    <BrainIcon />
                    <span>분석</span>
                  </div>
                </button>
              </div>

              {/* 탭 콘텐츠 */}
              <div className="p-6" style={{ minHeight: '200px', maxHeight: '300px' }}>
                {activeTab === 'detection' && (
                  <div className="h-full overflow-y-auto">
                    <h3 className="font-semibold text-gray-800 mb-4">식품 탐지 결과</h3>
                    {detectionResults ? (
                      <div className="space-y-3">
                        <div className="text-sm text-gray-600 mb-3">
                          총 {detectionResults.detections?.length || 0}개 탐지 (표시만, 대시보드 추가 안됨)
                        </div>
                        {detectionResults.detections?.map((detection, index) => (
                          <div key={index} className="p-3 bg-gray-50 rounded-xl">
                            <div className="flex justify-between items-center">
                              <span className="font-medium text-blue-600">
                                {detection.class}
                              </span>
                              <span className="text-sm font-semibold px-3 py-1 rounded-full bg-green-100 text-green-700">
                                {(detection.confidence * 100).toFixed(1)}%
                              </span>
                            </div>
                          </div>
                        )) || <p className="text-gray-500">탐지된 객체가 없습니다.</p>}
                      </div>
                    ) : (
                      <p className="text-gray-500">탐지 결과가 없습니다.</p>
                    )}
                  </div>
                )}

                {activeTab === 'ocr' && (
                  <div className="h-full overflow-y-auto">
                    <h3 className="font-semibold text-gray-800 mb-4">OCR 텍스트</h3>
                    <div className="bg-gray-50 rounded-xl p-4 min-h-[150px]">
                      <p className="text-gray-700 whitespace-pre-wrap break-words leading-relaxed">
                        {ocrResults || '추출된 텍스트가 없습니다.'}
                      </p>
                    </div>
                  </div>
                )}

                {activeTab === 'gemini' && (
                  <div className="h-full overflow-y-auto">
                    <h3 className="font-semibold text-gray-800 mb-4">AI 분석 결과</h3>
                    <div className="bg-gray-50 rounded-xl p-4 min-h-[150px]">
                      <p className="text-gray-700 whitespace-pre-wrap break-words leading-relaxed">
                        {geminiResults || '분석 결과가 없습니다.'}
                      </p>
                    </div>
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>

        {/* 상태바 */}
        <div className="mt-6 bg-white rounded-2xl shadow-sm p-4">
          <div className="flex items-center gap-3">
            <div className="w-3 h-3 bg-green-500 rounded-full animate-pulse"></div>
            <span className="text-gray-700 flex-1 font-medium">
              {statusMessage}
            </span>
          </div>
        </div>
      </div>
    </div>
  );
};

export default FoodDetectionApp;
